class Solution:
    def findPermutationDifference(self, s: str, t: str) -> int:
        # Create a dictionary to map each character to its index in s
        char_to_index = {char: idx for idx, char in enumerate(s)}

        # Calculate the permutation difference
        total_diff = 0
        for idx, char in enumerate(t):
            total_diff += abs(idx - char_to_index[char])

        return total_diff
